// 校对图编号格式：检查"图章节号。序号"格式，如"图 3.2"、"图 1.1"等
var doc = Application.ActiveDocument;
var range = doc.Content;
var paragraphs = range.Paragraphs;
var results = {
  total: 0,
  matched: 0,
  errors: [],
  fixed: 0
};

// 正则表达式匹配图编号：图 + 数字 + 点 + 数字（支持多级如 3.1.2）
var figurePattern = /图 (\d+(?:\.\d+)*)/g;

for (var i = 1; i <= paragraphs.Count; i++) {
  var para = paragraphs.Item(i);
  var text = para.Range.Text;
  // 去掉段落标记
  if (text.endsWith("\n")) {
    text = text.slice(0, -1);
  }
  if (text.endsWith("\r")) {
    text = text.slice(0, -1);
  }

  // 检查是否包含图编号
  var match;
  while ((match = figurePattern.exec(text)) !== null) {
    results.total++;
    var fullMatch = match[0]; // 如 "图 3.2"
    var numberPart = match[1]; // 如 "3.2"

    // 检查编号格式是否正确（章节号。序号）
    var parts = numberPart.split('.');
    if (parts.length >= 2 && parts.length <= 3) {
      // 格式正确：至少 2 部分（章。序），最多 3 部分（章。节.序）
      results.matched++;
    } else {
      // 格式错误
      results.errors.push({
        paragraph: i,
        original: fullMatch,
        message: "图编号格式不正确，应为'图章节号。序号'格式"
      });
    }
  }
}

return {
  success: true,
  totalFigures: results.total,
  correctFormat: results.matched,
  incorrectFormat: results.errors.length,
  errorDetails: results.errors.slice(0, 10) // 只返回前 10 个错误
};
